import React, { useEffect, useState } from "react";
import axios from "axios";
import { Card, Container, Row, Col } from "react-bootstrap";
import { Pie } from "react-chartjs-2";

const ReconciliationDashboard = () => {
  const [summary, setSummary] = useState({});

  useEffect(() => {
    axios.get("http://localhost:4000/api/dashboard/summary")
      .then(res => setSummary(res.data))
      .catch(err => console.error("Error loading dashboard data:", err));
  }, []);

  const chartData = {
    labels: ["Matched", "Partial", "Duplicate", "Unmatched"],
    datasets: [
      {
        data: [summary.matched, summary.partial, summary.duplicate, summary.unmatched],
        backgroundColor: ["#28a745", "#ffc107", "#6f42c1", "#dc3545"],
      },
    ],
  };

  return (
    <Container className="mt-4">
      <h3>Reconciliation Dashboard</h3>
      <Row className="mt-3">
        <Col><Card><Card.Body>Total Records: {summary.total}</Card.Body></Card></Col>
        <Col><Card><Card.Body>Matched: {summary.matched}</Card.Body></Card></Col>
        <Col><Card><Card.Body>Partial: {summary.partial}</Card.Body></Card></Col>
        <Col><Card><Card.Body>Duplicate: {summary.duplicate}</Card.Body></Card></Col>
        <Col><Card><Card.Body>Unmatched: {summary.unmatched}</Card.Body></Card></Col>
      </Row>

      <div className="mt-4" style={{ width: "400px", margin: "auto" }}>
        <Pie data={chartData} />
      </div>
    </Container>
  );
};

export default ReconciliationDashboard;
